  1→import { Element, Listen, Fragment, Component, Prop, h, State, Host } from '@stencil/core';
  2→import { getServiceNumber } from '../../utils/ttarp';
  3→import { setFeatureFlagsFromUrl, signaler } from '../../utils/signaler';
  4→import phone from '../../assets/header/phone_icon.svg';
  5→import helpIcon from '../../assets/help-circle.svg';
  6→import logoLargeHorizontal from '../../assets/logo-large-horizontal.svg';
  7→import { desktopBannerMessage, isBrowser, mobileBannerMessage } from '../../constants/constants';
  8→import { profilesClient } from '../../utils/auth/profilesClient';
  9→import { USER_AUTHENTICATED_EVENT } from '../../utils/auth/windowMessages';
 10→import logo from '../../assets/logo.svg';
 11→import arrowDown from '../../assets/arrow_down.svg';
 12→import { trackAnalyticsEvent } from '../../utils/analytics';
 13→import { isUserLoggedIn as _isUserLoggedIn } from '../../utils/is_user_logged_in';
 14→import { toAccountsLink } from '../../constants/constants';
 15→import { signalmizelyHelpers } from '../../utils/signalmizely';
 16→import { createAccountsKeyDownHandler } from '../../utils/panel-keyboard-navigation';
 17→
 18→@Component({
 19→  tag: 'ci-header',
 20→  styleUrl: 'ci-header.scss',
 21→  assetsDirs: ['.../assets'],
 22→  scoped: true,
 23→})
 24→export class CustominkHeader {
 25→  @Element() $el: HTMLElement;
 26→  @Prop() serviceNumber: string; // Allow an optional serviceNumber prop
 27→  @Prop() mobileBannerMessage: string = mobileBannerMessage;
 28→  @Prop() desktopBannerMessage: string = desktopBannerMessage;
 29→  @Prop() simple = false;
 30→  @Prop() showCart = true;
 31→  @Prop() cartDetail = false;
 32→  @Prop() cartPricing = false;
 33→  @Prop() detailedQuantities = false;
 34→  @Prop() usePopupLogin = false;
 35→  @State() signaler = signaler;
 36→  @State() dynamicServiceNumber: string = '';
 37→  @State() isFramer: boolean;
 38→  @State() visibleMenuBtn: boolean;
 39→  @State() showMenu: boolean;
 40→  @State() visibleMobileVisibility: boolean;
 41→  @State() visibleOverlay: boolean;
 42→  @State() isUserLoggedIn: boolean = _isUserLoggedIn();
 43→  @State() chatPopupOpen: boolean = false;
 44→  private dialog!: HTMLCiDialogElement;
 45→  @State() isPromoEnabled: boolean = false;
 46→
 47→  private handleVisibilityChange = () => {
 48→    if (document.visibilityState === 'visible') {
 49→      this.isUserLoggedIn = _isUserLoggedIn();
 50→    }
 51→  };
 52→
 53→  async componentWillLoad() {
 54→    if (isBrowser) {
 55→      setFeatureFlagsFromUrl(this.signaler);
 56→      window.dispatchEvent(new Event('ciHeaderLoaded'));
 57→
 58→      // If serviceNumber prop is not provided, fetch the dynamic service number
 59→      if (!this.serviceNumber) {
 60→        const fetchedServiceNumber = await getServiceNumber(); // Wait for the service number to resolve
 61→        this.dynamicServiceNumber = fetchedServiceNumber;
 62→      } else {
 63→        this.dynamicServiceNumber = this.serviceNumber;
 64→      }
 65→
 66→      const url = window.location.href;
 67→      this.isFramer = url.includes('iframer');
 68→    }
 69→  }
 70→
 71→  connectedCallback() {
 72→    if (isBrowser) {
 73→      // Re-check login status when tab becomes visible (handles popup auth flow)
 74→      document.addEventListener('visibilitychange', this.handleVisibilityChange);
 75→    }
 76→  }
 77→
 78→  disconnectedCallback() {
 79→    if (isBrowser) {
 80→      document.removeEventListener('visibilitychange', this.handleVisibilityChange);
 81→    }
 82→  }
 83→
 84→  async componentDidLoad() {
 85→    if (isBrowser) {
 86→      try {
 87→        const hatsPromoFlag = await signalmizelyHelpers.flagVariation('sitewide_february_sweats_promo');
 88→        this.isPromoEnabled = hatsPromoFlag === 'test';
 89→      } catch (error) {
 90→        this.isPromoEnabled = false;
 91→      }
 92→    }
 93→  }
 94→
 95→  async handleSignIn(event: MouseEvent | TouchEvent) {
 96→    const result = await profilesClient.loginWithPopup();
 97→    this.isUserLoggedIn = result.isAuthenticated;
 98→    if (result.isAuthenticated) {
 99→      window.dispatchEvent(new Event(USER_AUTHENTICATED_EVENT));
100→      this.getAccountsModal(event.target).forceClose();
101→    }
102→  }
103→
104→  async handleSignUp() {
105→    const result = await profilesClient.loginWithPopup({
106→      screen_hint: 'signup',
107→    });
108→    this.isUserLoggedIn = result.isAuthenticated;
109→    if (result.isAuthenticated) {
110→      window.dispatchEvent(new Event(USER_AUTHENTICATED_EVENT));
111→    }
112→  }
113→
114→  handleSignOut() {
115→    profilesClient.logout();
116→  }
117→
118→  private hideMenuTimeout: number;
119→
120→  @Listen('pointerdown', { target: 'document' })
121→  handleOutsideInteraction(event: PointerEvent) {
122→    const componentRoot = this.$el;
123→    if (!componentRoot.contains(event.target as Node)) {
124→      this.showMenu = false;
125→    }
126→  }
127→
128→  @Listen('keydown', { target: 'document' })
129→  handleEscapeKey(event: KeyboardEvent) {
130→    if (event.key === 'Escape' && this.showMenu) {
131→      this.getAccountsModal(event.target).closeModal(event);
132→    }
133→  }
134→
135→  private getAccountsModal(target: EventTarget): HTMLCiDialogElement | null {
136→    const parent = (target as HTMLElement).closest('.accounts');
137→    const accountsEl = parent?.querySelector('ci-accounts');
138→    return accountsEl.shadowRoot.querySelector('ci-dialog');
139→  }
140→
141→  private handleMouseEnter = event => {
142→    window.clearTimeout(this.hideMenuTimeout);
143→    this.getAccountsModal(event.target).openModal(event);
144→  };
145→
146→  private handleMouseLeave = event => {
147→    this.hideMenuTimeout = window.setTimeout(() => {
148→      this.getAccountsModal(event.target).closeModal(event);
149→    }, 200);
150→  };
151→
152→  private handleTouchStart = (e: Event) => {
153→    e.preventDefault();
154→    this.getAccountsModal(e.target).openModal(e);
155→  };
156→
157→  private handleTouchEnd = (e: Event) => {
158→    e.preventDefault();
159→  };
160→
161→  private handleAccountsKeyDown = createAccountsKeyDownHandler(this.getAccountsModal.bind(this));
162→
163→  private renderHelpMenu() {
164→    return (
165→      <div class="customer-help">
166→        {this.simple && (
167→          <Fragment>
168→            <ci-dialog name="We’re Here To Help" ref={el => (this.dialog = el)}>
169→              <p id="customer-subtitle" slot="dialog-content">
170→                Need a hand? Get personalized support from our expert team.
171→              </p>
172→              <div class="customer-actions" slot="dialog-actions">
173→                <a href={`tel:${this.dynamicServiceNumber}`} class="tertiary-secondary-button">
174→                  <customer-contact serviceNumber={this.dynamicServiceNumber}></customer-contact>
175→                </a>
176→                <button onClick={this.handleShowChat}>
177→                  <customer-chat />
178→                </button>
179→              </div>
180→            </ci-dialog>
181→            <button id="customer-btn" onClick={this.handleShowModal}>
182→              <img src={helpIcon} alt="phone icon" class="customer-help-icon" />
183→              <span>Help</span>
184→            </button>
185→          </Fragment>
186→        )}
187→        <customer-contact serviceNumber={this.dynamicServiceNumber}></customer-contact>
188→        <customer-chat></customer-chat>
189→      </div>
190→    );
191→  }
192→
193→  private renderAccountContent() {
194→    return (
195→      <Fragment>
196→        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none">
197→          <path
198→            fill-rule="evenodd"
199→            clip-rule="evenodd"
200→            d="M17.5 7.5C17.5 10.5376 15.0376 13 12 13C8.96243 13 6.5 10.5376 6.5 7.5C6.5 4.46243 8.96243 2 12 2C15.0376 2 17.5 4.46243 17.5 7.5ZM8 16.5C6.34315 16.5 5 17.8431 5 19.5V21C5 21.5523 4.55228 22 4 22C3.44772 22 3 21.5523 3 21V19.5C3 16.7386 5.23858 14.5 8 14.5H16C18.7614 14.5 21 16.7386 21 19.5V21C21 21.5523 20.5523 22 20 22C19.4477 22 19 21.5523 19 21V19.5C19 17.8431 17.6569 16.5 16 16.5H8ZM12 11C13.933 11 15.5 9.433 15.5 7.5C15.5 5.567 13.933 4 12 4C10.067 4 8.5 5.567 8.5 7.5C8.5 9.433 10.067 11 12 11Z"
201→            fill="#4A4A4A"
202→          />
203→        </svg>
204→        <span class="ciHeader-accounts-btn-text">{this.isUserLoggedIn ? 'My Account' : 'Sign In'}</span>
205→        {this.simple && <span class="ciHeader-accounts-btn-text--mobile">{this.isUserLoggedIn ? 'Account' : 'Sign In'}</span>}
206→      </Fragment>
207→    );
208→  }
209→
210→  private renderAccount() {
211→    if (!this.isUserLoggedIn && this.usePopupLogin) {
212→      return (
213→        <button
214→          class="ciHeader-accounts-btn-popup"
215→          data-section="my account"
216→          data-link="my-account-login"
217→          data-testid="my-account"
218→          onTouchStart={this.handleTouchStart}
219→          onTouchEnd={this.handleTouchEnd}
220→          onKeyDown={e => this.handleAccountsKeyDown(e, false)}
221→          onClick={e => {
222→            trackAnalyticsEvent(e);
223→            if (!this.isUserLoggedIn) {
224→              this.handleSignIn(e);
225→            }
226→          }}
227→        >
228→          {this.renderAccountContent()}
229→        </button>
230→      );
231→    }
232→
233→    return (
234→      <a
235→        href={toAccountsLink(this.isUserLoggedIn)}
236→        class="ciHeader-accounts-btn"
237→        onTouchStart={this.handleTouchStart}
238→        onTouchEnd={this.handleTouchEnd}
239→        onKeyDown={e => this.handleAccountsKeyDown(e, false)}
240→        data-section="my account"
241→        data-link="my account"
242→        data-testid="my-account"
243→        onClick={event => {
244→          trackAnalyticsEvent(event);
245→          if (this.simple && this.isUserLoggedIn) {
246→            event.preventDefault();
247→          }
248→        }}
249→      >
250→        {this.renderAccountContent()}
251→      </a>
252→    );
253→  }
254→
255→  private renderCartAndAccount() {
256→    return (
257→      <Fragment>
258→      {!this.simple && <ci-favorites
259→          dataSection="favorites"
260→          dataLink="favorites"
261→        />}
262→        <div class="accounts" onMouseEnter={this.handleMouseEnter} onMouseLeave={this.handleMouseLeave}>
263→          <div class="accounts-trigger-group">
264→            {this.renderAccount()}
265→            <button
266→              type="button"
267→              class="accounts-caret"
268→              aria-haspopup="true"
269→              aria-label={this.isUserLoggedIn ? 'Open My Account menu' : 'Open Sign In menu'}
270→              onClick={e => this.getAccountsModal(e.target)?.openModal(e)}
271→              onKeyDown={e => this.handleAccountsKeyDown(e, true)}
272→            >
273→              <img src={arrowDown} class="accounts-caret-icon" alt="" />
274→            </button>
275→          </div>
276→
277→          <ci-accounts
278→            isUserLogged={this.isUserLoggedIn}
279→            isSimple={this.simple}
280→            usePopupLogin={this.usePopupLogin}
281→            onSignIn={this.handleSignIn.bind(this)}
282→            onSignUp={this.handleSignUp.bind(this)}
283→            onSignOut={this.handleSignOut.bind(this)}
284→          >
285→            <slot name="accounts-menu" />
286→          </ci-accounts>
287→        </div>
288→        {this.showCart && (
289→          <ci-cart
290→            pricing={this.cartPricing}
291→            detail={this.cartDetail}
292→            detailedQuantities={this.detailedQuantities}
293→            data-section="my cart"
294→            data-link="my cart"
295→            onClick={trackAnalyticsEvent}
296→          />
297→        )}
298→      </Fragment>
299→    );
300→  }
301→
302→  private handleShowModal = e => {
303→    this.dialog.openModal(e);
304→  };
305→
306→  private handleShowChat = e => {
307→    e.preventDefault();
308→    (this.$el.querySelector('#LP_') as HTMLElement)?.click();
309→    this.dialog.forceClose();
310→  };
311→
312→  private handleSkipLink = (e: MouseEvent) => {
313→    e.preventDefault();
314→    const mainContent = (document.querySelector('main') || document.getElementById('root')) as HTMLElement;
315→    if (mainContent) {
316→      mainContent.setAttribute('tabindex', '-1');
317→      mainContent.focus();
318→      mainContent.scrollIntoView({ behavior: 'smooth' });
319→    }
320→  };
321→
322→  render() {
323→    const onMenuBtnClick = () => {
324→      this.visibleMenuBtn = !this.visibleMenuBtn;
325→      const ciBodyTag = document.getElementsByTagName('body')[0] as HTMLElement;
326→
327→      if (this.visibleMenuBtn) {
328→        this.visibleMobileVisibility = !this.visibleMobileVisibility;
329→        // Hotfix body scrolling issue on iOS 26. Backwards compatible for older versions. Works both on Android and iOS.
330→        ciBodyTag.style.position = 'fixed';
331→        ciBodyTag.style.width = '100%';
332→        ciBodyTag.style.overflow = 'hidden';
333→      } else {
334→        setTimeout(() => {
335→          this.visibleMobileVisibility = !this.visibleMobileVisibility;
336→          // Hotfix body scrolling issue on iOS 26. Backwards compatible for older versions. Works both on Android and iOS.
337→          ciBodyTag.style.position = '';
338→          ciBodyTag.style.top = '';
339→          ciBodyTag.style.width = '';
340→          ciBodyTag.style.overflow = 'visible';
341→        }, 200);
342→      }
343→    };
344→    return (
345→      <Host>
346→        <a href="#main-content" class="skip-link" onClick={this.handleSkipLink}>
347→          Skip to main content
348→        </a>
349→        <div
350→          class={{
351→            overlay: true,
352→            activeOverlay: this.visibleOverlay,
353→            closeOverlay: !this.visibleOverlay,
354→          }}
355→        />
356→        {!this.simple && isBrowser && <ci-announcement-banner isPromoEnabled={this.isPromoEnabled} />}
357→        {!this.simple && isBrowser && !this.isPromoEnabled && (
358→          <div class="banner-container">
359→            <div class="banner">
360→              <div class="banner-title">
361→                <span class="banner-title--desktop">{this.desktopBannerMessage}</span>
362→                <span class="banner-title--mobile">{this.mobileBannerMessage}</span>
363→              </div>
364→              <div class="banner-actions">
365→                <button
366→                  class="banner-ttarpMobile ciHeader-phoneNumberLink"
367→                  data-section="mobile banner"
368→                  data-link="help"
369→                  onClick={e => {
370→                    trackAnalyticsEvent(e);
371→                    this.chatPopupOpen = true;
372→                  }}
373→                >
374→                  <img class="banner-ttarpMobile-icon" src={phone} alt="phone icon" />
375→                  <span class="banner-ttarpMobile-text">Help</span>
376→                </button>
377→              </div>
378→            </div>
379→          </div>
380→        )}
381→        <div class="main-container">
382→          <div
383→            class={{
384→              ciHeader: true,
385→              simple: this.simple,
386→            }}
387→          >
388→            <div class="ciHeader-subNav">
389→              <div
390→                class={{
391→                  'ciHeader-mobile-menu-btn': true,
392→                  'active': this.visibleMenuBtn,
393→                }}
394→                id="menuButton"
395→                onClick={onMenuBtnClick}
396→              >
397→                <span />
398→                <span />
399→                <span />
400→              </div>
401→              <ci-mobile-subnav
402→                isUserLogged={this.isUserLoggedIn}
403→                serviceNumber={this.dynamicServiceNumber}
404→                visible={this.visibleMobileVisibility}
405→                visibleDrawer={this.visibleMenuBtn}
406→                onCloseDrawer={onMenuBtnClick}
407→              ></ci-mobile-subnav>
408→              <a href={`${process.env.CI_HOSTNAME}`} class="ciHeader-logo" role="link">
409→                <picture>
410→                  {this.simple && <source media="(max-width: 699px)" srcSet={logo} />}
411→                  <img alt="customink logo - inky" class="ciHeader-logo-image" src={logoLargeHorizontal} />
412→                </picture>
413→              </a>
414→            </div>
415→            {!this.simple && !this.isFramer && <ci-search id="searchOverlay"></ci-search>}
416→            {this.renderHelpMenu()}
417→            {this.renderCartAndAccount()}
418→            <slot />
419→          </div>
420→        </div>
421→        {!this.simple && (
422→          <div class="navigation-container">
423→            <div class="navigation">
424→              <ci-navigation
425→                onOpenOverlay={() => {
426→                  this.visibleOverlay = true;
427→                }}
428→                onCloseOverlay={() => {
429→                  this.visibleOverlay = false;
430→                }}
431→              ></ci-navigation>
432→              {this.renderCartAndAccount()}
433→            </div>
434→          </div>
435→        )}
436→        {!this.simple && <ci-chat-popup open={this.chatPopupOpen} serviceNumber={this.dynamicServiceNumber} onClose={() => (this.chatPopupOpen = false)} />}
437→      </Host>
438→    );
439→  }
440→}
