  1→import { Component, Prop, h } from '@stencil/core';
  2→import { autocomplete, getAlgoliaFacets, getAlgoliaResults } from '@algolia/autocomplete-js';
  3→import { createLocalStorageRecentSearchesPlugin } from '@algolia/autocomplete-plugin-recent-searches';
  4→import { createQuerySuggestionsPlugin } from '@algolia/autocomplete-plugin-query-suggestions';
  5→import { createRedirectUrlPlugin } from '@algolia/autocomplete-plugin-redirect-url';
  6→import Cookies from 'js-cookie';
  7→import { autoCompleteFacets, indexName, isBrowser, searchClient, showFourHitsPerPage, showSixHitsPerPage, suggestedQueriesIndexName } from '../../constants/constants';
  8→import { handleAutocompleteSelection, passThruSearchParams } from '../../utils/algoliaAutoComplete';
  9→import { getQueryParamValue, getImageUrl, getAbsoluteUrl } from '../../utils/url';
 10→
 11→@Component({
 12→  tag: 'ci-search',
 13→  styleUrl: 'ci-search.scss',
 14→})
 15→export class ciSearch {
 16→  @Prop() isItForPrerenderedView: boolean = false;
 17→  private autocompleteContainer!: HTMLDivElement;
 18→
 19→  private setupSearch() {
 20→    const recentSearchesPlugin = createLocalStorageRecentSearchesPlugin({
 21→      key: 'ALG_CAT_RECENT_SEARCH',
 22→      limit: 6,
 23→      transformSource({ source }) {
 24→        return {
 25→          ...source,
 26→          onSelect: ({ item }) => handleAutocompleteSelection(searchClient, indexName, item.label),
 27→          templates: {
 28→            header() {
 29→              return 'Recent Searches';
 30→            },
 31→            ...source.templates,
 32→          },
 33→        };
 34→      },
 35→    });
 36→
 37→    const querySuggestionsPlugin = createQuerySuggestionsPlugin({
 38→      searchClient,
 39→      indexName: suggestedQueriesIndexName,
 40→      getSearchParams({ state }) {
 41→        return {
 42→          hitsPerPage: state.query ? showSixHitsPerPage : showFourHitsPerPage,
 43→        };
 44→      },
 45→
 46→      transformSource({ source }) {
 47→        return {
 48→          ...source,
 49→          onSelect: ({ item }) => handleAutocompleteSelection(searchClient, indexName, item.query),
 50→          templates: {
 51→            header() {
 52→              return 'Suggestions';
 53→            },
 54→            ...source.templates,
 55→          },
 56→        };
 57→      },
 58→    });
 59→    const oeUserToken = Cookies.get('oe');
 60→    if (oeUserToken && typeof window.aa === 'function') {
 61→      window.aa('setUserToken', oeUserToken.substring(0, 64));
 62→    }
 63→
 64→    const redirectUrlPlugin = createRedirectUrlPlugin();
 65→
 66→    autocomplete({
 67→      container: this.autocompleteContainer,
 68→      plugins: [recentSearchesPlugin, querySuggestionsPlugin, redirectUrlPlugin],
 69→      openOnFocus: true,
 70→      insights: true,
 71→      placeholder: 'Search for t-shirts, hoodies, koozies, and more',
 72→      initialState: {
 73→        query: getQueryParamValue('keyword'),
 74→      },
 75→      getSources({ query }) {
 76→        const searchParams = new URLSearchParams(document.location.search);
 77→        const compatibleTypeFilter = searchParams.get('compatible_type');
 78→        let mappedFilters = '(status:active)';
 79→        let facetFilters = [];
 80→        if (compatibleTypeFilter) facetFilters.push(`compatible_type:${compatibleTypeFilter}`);
 81→        const sources = [];
 82→
 83→        autoCompleteFacets.forEach(facet => {
 84→          sources.push({
 85→            sourceId: `facet_${facet.name}`,
 86→            getItems({ query }) {
 87→              if (!query) return [];
 88→              return getAlgoliaFacets({
 89→                searchClient,
 90→                queries: [
 91→                  {
 92→                    indexName: indexName,
 93→                    facet: facet.name,
 94→                    params: {
 95→                      facetQuery: query,
 96→                      maxFacetHits: facet.showNum || 6,
 97→                      clickAnalytics: true,
 98→                    },
 99→                  },
100→                ],
101→              });
102→            },
103→
104→            templates: {
105→              header({ items }) {
106→                if (!items.length) return null;
107→                return facet.caption;
108→              },
109→              item({ item, html, components }) {
110→                return html`<div>
111→                  <div class="aa-ItemTitle">${(<components.Highlight hit={item} attribute="label" tagName="mark" />)}</div>
112→                </div> `;
113→              },
114→            },
115→            onSelect: ({ item }) => handleAutocompleteSelection(searchClient, indexName, item.label),
116→          });
117→        });
118→        sources.push({
119→          sourceId: 'styles',
120→          getItems() {
121→            if (!query) return [];
122→            return getAlgoliaResults({
123→              searchClient,
124→              queries: [
125→                {
126→                  indexName: indexName,
127→                  query,
128→                  params: {
129→                    hitsPerPage: 6,
130→                    filters: mappedFilters,
131→                    facetFilters: facetFilters,
132→                    clickAnalytics: true,
133→                  },
134→                },
135→              ],
136→            });
137→          },
138→          templates: {
139→            header({ items }) {
140→              if (!items.length) return null;
141→              return 'Results for Styles';
142→            },
143→            item({ item, html, components }) {
144→              return html` <a href=${getAbsoluteUrl(item.url)} class="aa-ItemLink" style-option status-${item.status}>
145→                <div class="aa-Item-Content">
146→                  <div style=${{ margin: '0 auto 5px' }}>
147→                    <img alt="Style Image" height="140" src=${getImageUrl(item)} />
148→                  </div>
149→                  <div class="aa-ItemTitle">${(<components.Highlight hit={item} attribute="name" tagName="mark" />)}</div>
150→                  <div><ci-rating ratingScore=${item.rating_score} ratingCount=${item.rating_count} name=${item.name} generalComments=${item.general_comments} /></div>
151→                </div>
152→              </a>`;
153→            },
154→            footer() {},
155→            noResults() {
156→              if (!query) return;
157→              const multipleNoResults = Array.from(document.querySelectorAll('.aa-SourceNoResults'));
158→              multipleNoResults.slice(1).forEach(element => element.remove());
159→              return 'No results';
160→            },
161→          },
162→          onSelect({ item }) {
163→            let path = '';
164→            if (item.target_url) path = item.target_url;
165→            if (item.breadcrumbs && item.breadcrumbs.length) {
166→              path = item.breadcrumbs[item.breadcrumbs.length - 1].path;
167→            }
168→            window.location.href = getAbsoluteUrl(passThruSearchParams(path));
169→          },
170→        });
171→        return sources;
172→      },
173→      getInputProps(params) {
174→        return {
175→          ...params.props,
176→          'aria-label': 'Search for products',
177→          'aria-labelledby': undefined,
178→        };
179→      },
180→    });
181→  }
182→  handleKeyDown(evt: KeyboardEvent) {
183→    const target = evt.target as HTMLInputElement;
184→    if (target.matches('.aa-Input')) {
185→      if (evt.key === 'Enter') {
186→        const qry = (evt.target as HTMLInputElement).value;
187→        if (qry.trim() === '') return;
188→        handleAutocompleteSelection(searchClient, indexName, qry.trim());
189→      }
190→      if (evt.key === ' ') {
191→        const el = evt.target as HTMLInputElement;
192→        let qry = el.value + evt.key;
193→        // remove 2+ spaces
194→        while (qry.indexOf('  ') >= 0) {
195→          qry = qry.replace(/  /g, ' ');
196→        }
197→        if (qry.endsWith(' ')) qry = qry.substring(0, qry.length - 1);
198→        el.value = qry;
199→      }
200→    }
201→  }
202→  componentDidLoad() {
203→    if (isBrowser) {
204→      this.setupSearch();
205→      document.addEventListener('keydown', this.handleKeyDown);
206→    }
207→  }
208→  render() {
209→    if (!this.isItForPrerenderedView && !isBrowser) {
210→      return null;
211→    }
212→
213→    if (this.isItForPrerenderedView && !isBrowser) {
214→      return (
215→        <div class="ciSearch">
216→          <div class="ciSearch-skeleton"></div>
217→        </div>
218→      );
219→    }
220→
221→    return (
222→      <div class="ciSearch">
223→        <div id="autocomplete" ref={el => (this.autocompleteContainer = el)}></div>
224→      </div>
225→    );
226→  }
227→}
