  1→import { State, Host, Element, Component, Prop, h, Method } from '@stencil/core';
  2→import { isBrowser } from '../../constants/constants';
  3→
  4→@Component({
  5→  tag: 'ci-dialog',
  6→  styleUrl: 'ci-dialog.scss',
  7→  assetsDirs: ['.../assets'],
  8→  shadow: true,
  9→})
 10→export class CiDialog {
 11→  @Element() $el: HTMLElement;
 12→  @State() mql: MediaQueryList;
 13→  @State() isLargeScreen: boolean = true; // Default to desktop for prerender
 14→  @State() showDialog: boolean = false;
 15→  @Prop() name: string;
 16→  private dialog: HTMLDialogElement;
 17→  private resizeTimeoutId: ReturnType<typeof setTimeout> | null = null;
 18→  private pendingOpenState: boolean = false; // Tracks intended open state during resize transitions
 19→
 20→  @Method()
 21→  async closeModal(event) {
 22→    this.pendingOpenState = false; // User explicitly closed, clear pending state
 23→    if (this.isLargeScreen) {
 24→      this.showDialog = false;
 25→    } else if(event.target.tagName === 'DIALOG') {
 26→      this.dialog?.close();
 27→    }
 28→  }
 29→
 30→  @Method()
 31→  async openModal(event) {
 32→    if (this.isLargeScreen) {
 33→      this.showDialog = !this.showDialog;
 34→    } else {
 35→      event.stopPropagation();
 36→      this.dialog?.showModal();
 37→    }
 38→  }
 39→
 40→  @Method()
 41→  async forceClose() {
 42→    this.pendingOpenState = false; // User explicitly closed, clear pending state
 43→    this.dialog?.close();
 44→  }
 45→
 46→  handleResize = (event: MediaQueryListEvent) => {
 47→    const wasLargeScreen = this.isLargeScreen;
 48→    // Check if dialog was open - only check this.dialog?.open when currently on mobile (not stale reference)
 49→    const wasOpen = this.showDialog || (!wasLargeScreen && this.dialog?.open) || this.pendingOpenState;
 50→    this.isLargeScreen = event.matches;
 51→
 52→    // Clear any pending timeout from previous resize
 53→    if (this.resizeTimeoutId !== null) {
 54→      clearTimeout(this.resizeTimeoutId);
 55→      this.resizeTimeoutId = null;
 56→    }
 57→
 58→    if (wasOpen) {
 59→      if (wasLargeScreen && !this.isLargeScreen) {
 60→        // Desktop -> Mobile: reset showDialog and switch to modal after re-render
 61→        this.showDialog = false;
 62→        this.pendingOpenState = true; // Preserve open intent during transition
 63→        this.resizeTimeoutId = setTimeout(() => {
 64→          this.resizeTimeoutId = null;
 65→          // Only open if pendingOpenState wasn't cleared by user close action
 66→          if (!this.pendingOpenState) return;
 67→          this.pendingOpenState = false;
 68→          const dialog = this.$el.shadowRoot?.querySelector('dialog') as HTMLDialogElement;
 69→          if (dialog && !dialog.open) {
 70→            dialog.showModal();
 71→          }
 72→        }, 0);
 73→      } else if (!wasLargeScreen && this.isLargeScreen) {
 74→        // Mobile -> Desktop: close modal and clear reference before switching to flyout
 75→        this.dialog?.close();
 76→        this.dialog = null;
 77→        this.pendingOpenState = false;
 78→        this.showDialog = true;
 79→      }
 80→    }
 81→  }
 82→
 83→  connectedCallback() {
 84→    if (!isBrowser) return;
 85→    this.mql = window.matchMedia("(min-width: 700px)");
 86→    this.isLargeScreen = this.mql.matches;
 87→    this.mql.addEventListener('change', this.handleResize);
 88→  }
 89→
 90→  disconnectedCallback() {
 91→    if (!isBrowser) return;
 92→    this.mql?.removeEventListener('change', this.handleResize);
 93→    if (this.resizeTimeoutId !== null) {
 94→      clearTimeout(this.resizeTimeoutId);
 95→      this.resizeTimeoutId = null;
 96→    }
 97→    this.pendingOpenState = false;
 98→  }
 99→
100→  renderContent() {
101→    return [
102→      <div part='header' class="dialog-header">
103→        <button
104→          autofocus
105→          onClick={this.forceClose.bind(this)}
106→          class="dialog-close" tabindex="0" type="button" aria-label="Close">
107→          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" class="dialog-close-icon" focusable="false" aria-hidden="true">
108→            <path
109→              fill-rule="evenodd"
110→              clip-rule="evenodd"
111→              d="M19.7071 5.70761C20.0976 5.31709 20.0976 4.68392 19.7071 4.29339C19.3166 3.90286 18.6834 3.90285 18.2929 4.29337L12 10.5861L5.70709 4.29337C5.31656 3.90285 4.6834 3.90286 4.29288 4.29339C3.90236 4.68392 3.90237 5.31709 4.29291 5.70761L10.5858 12.0002L4.29291 18.2929C3.90237 18.6834 3.90236 19.3166 4.29288 19.7071C4.6834 20.0976 5.31656 20.0976 5.70709 19.7071L12 13.4144L18.2929 19.7071C18.6834 20.0976 19.3166 20.0976 19.7071 19.7071C20.0976 19.3166 20.0976 18.6834 19.7071 18.2929L13.4142 12.0002L19.7071 5.70761Z"
112→              fill=""
113→            />
114→          </svg>
115→        </button>
116→        <h2 class="dialog-title">
117→          {this.name}
118→        </h2>
119→      </div>,
120→      <div part='content' class="dialog-content">
121→        <slot name="dialog-content" />
122→      </div>,
123→      <div part='actions' class="dialog-actions">
124→        <slot name="dialog-actions" />
125→      </div>
126→    ];
127→  }
128→
129→  render() {
130→    return (
131→      <Host>
132→        {this.isLargeScreen ? (
133→          <div
134→            class={{
135→              'dialog-flyout': true,
136→              'dialog-flyout--open': this.showDialog
137→            }}>
138→            <div part='surface' class="dialog-surface">
139→              {this.renderContent()}
140→            </div>
141→          </div>
142→        ) : (
143→          <dialog
144→            class='dialog-overlay'
145→            ref={(el) => this.dialog = el}
146→            onClick={this.closeModal.bind(this)}
147→          >
148→            <div part='surface' class="dialog-surface">
149→              {this.renderContent()}
150→            </div>
151→          </dialog>
152→        )}
153→      </Host>
154→    );
155→  }
156→}
