 107→
 108→// Note:
 109→// This theme reflects the markup structure of autocomplete with SCSS indentation.
 110→// We use the SASS `@at-root` function to keep specificity low.
 111→
 112→// ----------------
 113→// 1. CSS Variables
 114→// ----------------
 115→:root,
 116→.ciHeader {
 117→  // Input
 118→  --aa-search-input-height: 40px;
 119→  --aa-input-icon-size: 20px;
 120→
 121→  // Size and spacing
 122→  --aa-base-unit: 16;
 123→  --aa-spacing-factor: 1;
 124→  --aa-spacing: calc(var(--aa-base-unit) * var(--aa-spacing-factor) * 1px);
 125→  --aa-spacing-half: calc(var(--aa-spacing) / 2);
 126→  --aa-panel-max-height: 650px;
 127→
 128→  // Z-index
 129→  --aa-base-z-index: 9999;
 130→
 131→  // Font
 132→  --aa-font-size: calc(var(--aa-base-unit) * 1px);
 133→  --aa-font-family: inherit;
 134→  --aa-font-weight-medium: 500;
 135→  --aa-font-weight-semibold: 600;
 136→  --aa-font-weight-bold: 700;
 137→
 138→  // Icons
 139→  --aa-icon-size: 20px;
 140→  --aa-icon-stroke-width: 1.6;
 141→  --aa-icon-color-rgb: 119, 119, 163;
 142→  --aa-icon-color-alpha: 1;
 143→  --aa-action-icon-size: 20px;
 144→
 145→  // Text colors
 146→  --aa-text-color-rgb: 38, 38, 39;
 147→  --aa-text-color-alpha: 1;
 148→  --aa-primary-color-rgb: 62, 52, 211;
 149→  --aa-primary-color-alpha: 0.2;
 150→  --aa-muted-color-rgb: 128, 126, 163;
 151→  --aa-muted-color-alpha: 0.6;
 152→
 153→  // Border colors
 154→  --aa-panel-border-color-rgb: 128, 126, 163;
 155→  --aa-panel-border-color-alpha: 0.3;
 156→  --aa-input-border-color-rgb: 128, 126, 163;
 157→  --aa-input-border-color-alpha: 0.8;
 158→
 159→  // Background colors
 160→  --aa-background-color-rgb: 255, 255, 255;
 161→  --aa-background-color-alpha: 1;
 162→  --aa-input-background-color-rgb: 255, 255, 255;
 163→  --aa-input-background-color-alpha: 1;
 164→  --aa-selected-color-rgb: 179, 173, 214;
 165→  --aa-selected-color-alpha: 0.205;
 166→  --aa-description-highlight-background-color-rgb: 245, 223, 77;
 167→  --aa-description-highlight-background-color-alpha: 0.5;
 168→
 169→  // Detached mode
 170→  --aa-detached-media-query: (max-width: 699px);
 171→  --aa-detached-modal-media-query: (min-width: 700px);
 172→  --aa-detached-modal-max-width: 699px;
 173→  --aa-detached-modal-max-height: 500px;
 174→  --aa-overlay-color-rgb: 115, 114, 129;
 175→  --aa-overlay-color-alpha: 0.4;
 176→
 177→  // Shadows
 178→  --aa-panel-shadow: 0 0 0 1px rgba(35, 38, 59, 0.1), 0 6px 16px -4px rgba(35, 38, 59, 0.15);
 179→
 180→  // Scrollbar
 181→  --aa-scrollbar-width: 13px;
 182→  --aa-scrollbar-track-background-color-rgb: 234, 234, 234;
 183→  --aa-scrollbar-track-background-color-alpha: 1;
 184→  --aa-scrollbar-thumb-background-color-rgb: var(--aa-background-color-rgb);
 185→  --aa-scrollbar-thumb-background-color-alpha: 1;
 186→
 187→  // Touch screens
 188→  @media (hover: none) and (pointer: coarse) {
 189→    --aa-spacing-factor: 1.2;
 190→    --aa-action-icon-size: 22px;
 191→  }
 192→}
