 194→// ----------------
 195→// 2. Dark Mode
 196→// ----------------
 197→body {
 198→  /* stylelint-disable selector-no-qualifying-type, selector-class-pattern */
 199→  &[data-theme='dark'],
 200→  &.dark {
 201→    // Text colors
 202→    --aa-text-color-rgb: 183, 192, 199;
 203→    --aa-primary-color-rgb: 146, 138, 255;
 204→    --aa-muted-color-rgb: 146, 138, 255;
 205→
 206→    // Background colors
 207→    --aa-input-background-color-rgb: 0, 3, 9;
 208→    --aa-background-color-rgb: 21, 24, 42;
 209→    --aa-selected-color-rgb: 146, 138, 255;
 210→    --aa-selected-color-alpha: 0.25;
 211→    --aa-description-highlight-background-color-rgb: 0 255 255;
 212→    --aa-description-highlight-background-color-alpha: 0.25;
 213→
 214→    // Icons
 215→    --aa-icon-color-rgb: 119, 119, 163;
 216→
 217→    // Shadows
 218→    --aa-panel-shadow: inset 1px 1px 0 0 rgb(44, 46, 64), 0 3px 8px 0 rgb(0, 3, 9);
 219→
 220→    // Scrollbar
 221→    --aa-scrollbar-track-background-color-rgb: 44, 46, 64;
 222→    --aa-scrollbar-thumb-background-color-rgb: var(--aa-background-color-rgb);
 223→  }
 224→
 225→  /* stylelint-enable selector-no-qualifying-type, selector-class-pattern */
 226→}
