 14→import { toAccountsLink } from '../../constants/constants';
 15→import { signalmizelyHelpers } from '../../utils/signalmizely';
 16→import { createAccountsKeyDownHandler } from '../../utils/panel-keyboard-navigation';
 17→
 18→@Component({
 19→  tag: 'ci-header-prerender',
 20→  styleUrl: 'ci-header-prerender.scss',
 21→  assetsDirs: ['.../assets'],
 22→  scoped: true,
 23→})
 24→export class CustominkHeaderPrerender {
 25→  @Element() $el: HTMLElement;
 26→  @Prop() serviceNumber: string; // Allow an optional serviceNumber prop
 27→  @Prop() mobileBannerMessage: string = mobileBannerMessage;
 28→  @Prop() desktopBannerMessage: string = desktopBannerMessage;
 29→  @Prop() simple = false;
 30→  @Prop() showCart = true;
 31→  @Prop() cartDetail = false;
 32→  @Prop() cartPricing = false;
 33→  @Prop() detailedQuantities = false;
 34→  @Prop() usePopupLogin = false;
 35→  @State() signaler = signaler;
 36→  @State() dynamicServiceNumber: string = '';
 37→  @State() isFramer: boolean;
 38→  @State() visibleMenuBtn: boolean;
 39→  @State() showMenu: boolean;
 40→  @State() visibleMobileVisibility: boolean;
 41→  @State() visibleOverlay: boolean;
 42→  @State() isUserLoggedIn: boolean = _isUserLoggedIn();
 43→  @State() isPromoEnabled: boolean = false;
 44→
 45→  private dialog!: HTMLCiDialogElement;
 46→
 47→  private handleVisibilityChange = () => {
 48→    if (document.visibilityState === 'visible') {
 49→      this.isUserLoggedIn = _isUserLoggedIn();
 50→    }
 51→  };
 52→
 53→  async componentWillLoad() {
 54→    if (isBrowser) {
 55→      setFeatureFlagsFromUrl(this.signaler);
 56→      window.dispatchEvent(new Event('ciHeaderLoaded'));
 57→
 58→      // If serviceNumber prop is not provided, fetch the dynamic service number
 59→      if (!this.serviceNumber) {
 60→        const fetchedServiceNumber = await getServiceNumber(); // Wait for the service number to resolve
 61→        this.dynamicServiceNumber = fetchedServiceNumber;
 62→      } else {
 63→        this.dynamicServiceNumber = this.serviceNumber;
 64→      }
 65→      const url = window.location.href;
 66→      this.isFramer = url.includes('iframer');
 67→    }
 68→  }
 69→
 70→  connectedCallback() {
 71→    if (isBrowser) {
 72→      // Re-check login status when tab becomes visible (handles popup auth flow)
 73→      document.addEventListener('visibilitychange', this.handleVisibilityChange);
 74→    }
 75→  }
 76→
 77→  disconnectedCallback() {
 78→    if (isBrowser) {
 79→      document.removeEventListener('visibilitychange', this.handleVisibilityChange);
 80→    }
 81→  }
 82→
 83→  async componentDidLoad() {
 84→    if (isBrowser) {
 85→      try {
 86→        const hatsPromoFlag = await signalmizelyHelpers.flagVariation('sitewide_february_sweats_promo');
 87→        this.isPromoEnabled = hatsPromoFlag === 'test';
 88→      } catch (error) {
 89→        this.isPromoEnabled = false;
 90→      }
 91→    }
 92→  }
 93→
 94→  async handleSignIn(event: MouseEvent | TouchEvent) {
 95→    if (!isBrowser || !profilesClient) return;
 96→    const result = await profilesClient.loginWithPopup();
 97→    this.isUserLoggedIn = result.isAuthenticated;
 98→    if (result.isAuthenticated) {
 99→      window.dispatchEvent(new Event(USER_AUTHENTICATED_EVENT));
100→      this.getAccountsModal(event.target).forceClose();
101→    }
102→  }
103→
104→  async handleSignUp() {
105→    if (!isBrowser || !profilesClient) return;
106→    const result = await profilesClient.loginWithPopup({
107→      screen_hint: 'signup',
108→    });
109→    this.isUserLoggedIn = result.isAuthenticated;
110→    if (result.isAuthenticated) {
111→      window.dispatchEvent(new Event(USER_AUTHENTICATED_EVENT));
112→    }
113→  }
114→
115→  handleSignOut() {
116→    if (!isBrowser || !profilesClient) return;
117→    profilesClient.logout();
118→  }
119→
120→  private hideMenuTimeout: number;
121→
122→  @Listen('pointerdown', { target: 'document' })
123→  handleOutsideInteraction(event: PointerEvent) {
124→    const componentRoot = this.$el;
125→    if (!componentRoot.contains(event.target as Node)) {
126→      this.showMenu = false;
127→    }
128→  }
129→
130→  @Listen('keydown', { target: 'document' })
131→  handleEscapeKey(event: KeyboardEvent) {
132→    if (event.key === 'Escape' && this.showMenu) {
133→      this.getAccountsModal(event.target).closeModal(event);
134→    }
135→  }
136→
137→  private getAccountsModal(target: EventTarget): HTMLCiDialogElement | null {
138→    const parent = (target as HTMLElement).closest('.accounts');
139→    const accountsEl = parent?.querySelector('ci-accounts');
140→    return accountsEl.shadowRoot.querySelector('ci-dialog');
141→  }
142→
143→  private handleMouseEnter = event => {
144→    window.clearTimeout(this.hideMenuTimeout);
145→    this.getAccountsModal(event.target).openModal(event);
146→  };
147→
148→  private handleMouseLeave = event => {
149→    this.hideMenuTimeout = window.setTimeout(() => {
150→      this.getAccountsModal(event.target).closeModal(event);
151→    }, 200);
152→  };
153→
154→  private handleTouchStart = (e: Event) => {
155→    e.preventDefault();
156→    this.getAccountsModal(e.target).openModal(e);
157→  };
158→
159→  private handleTouchEnd = (e: Event) => {
160→    e.preventDefault();
161→  };
162→
163→  private handleAccountsKeyDown = createAccountsKeyDownHandler(this.getAccountsModal.bind(this));
164→
165→  private renderHelpMenu() {
166→    return (
167→      <div class="customer-help">
168→        {this.simple && (
169→          <Fragment>
170→            <ci-dialog name="We’re Here To Help" ref={el => (this.dialog = el)}>
171→              <p id="customer-subtitle" slot="dialog-content">
172→                Need a hand? Get personalized support from our expert team.
173→              </p>
174→              <div class="customer-actions" slot="dialog-actions">
175→                <a href={`tel:${this.dynamicServiceNumber}`} class="tertiary-secondary-button">
176→                  <customer-contact serviceNumber={this.dynamicServiceNumber} isItForPrerenderedView={true}></customer-contact>
177→                </a>
178→                <button onClick={this.handleShowChat}>
179→                  <customer-chat isItForPrerenderedView={true} />
180→                </button>
181→              </div>
182→            </ci-dialog>
183→            <button id="customer-btn" onClick={this.handleShowModal}>
184→              <img src={helpIcon} alt="phone icon" class="customer-help-icon" />
185→              <span>Help</span>
186→            </button>
187→          </Fragment>
188→        )}
189→        <customer-contact serviceNumber={this.dynamicServiceNumber} isItForPrerenderedView={true}></customer-contact>
190→        <customer-chat isItForPrerenderedView={true}></customer-chat>
191→      </div>
192→    );
193→  }
194→
195→  private renderAccountContent() {
196→    return (
197→      <Fragment>
198→        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none">
199→          <path
200→            fill-rule="evenodd"
201→            clip-rule="evenodd"
202→            d="M17.5 7.5C17.5 10.5376 15.0376 13 12 13C8.96243 13 6.5 10.5376 6.5 7.5C6.5 4.46243 8.96243 2 12 2C15.0376 2 17.5 4.46243 17.5 7.5ZM8 16.5C6.34315 16.5 5 17.8431 5 19.5V21C5 21.5523 4.55228 22 4 22C3.44772 22 3 21.5523 3 21V19.5C3 16.7386 5.23858 14.5 8 14.5H16C18.7614 14.5 21 16.7386 21 19.5V21C21 21.5523 20.5523 22 20 22C19.4477 22 19 21.5523 19 21V19.5C19 17.8431 17.6569 16.5 16 16.5H8ZM12 11C13.933 11 15.5 9.433 15.5 7.5C15.5 5.567 13.933 4 12 4C10.067 4 8.5 5.567 8.5 7.5C8.5 9.433 10.067 11 12 11Z"
203→            fill="#4A4A4A"
204→          />
205→        </svg>
206→        <span class="ciHeader-accounts-btn-text">{this.isUserLoggedIn ? 'My Account' : 'Sign In'}</span>
207→        {this.simple && <span class="ciHeader-accounts-btn-text--mobile">{this.isUserLoggedIn ? 'Account' : 'Sign In'}</span>}
208→      </Fragment>
209→    );
210→  }
211→
212→  private renderAccount() {
213→    if (!this.isUserLoggedIn && this.usePopupLogin) {
214→      return (
215→        <button
216→          class="ciHeader-accounts-btn-popup"
217→          data-section="my account"
218→          data-link="my-account-login"
219→          data-testid="my-account"
220→          onTouchStart={this.handleTouchStart}
221→          onTouchEnd={this.handleTouchEnd}
222→          onKeyDown={e => this.handleAccountsKeyDown(e, false)}
