239→        onTouchStart={this.handleTouchStart}
240→        onTouchEnd={this.handleTouchEnd}
241→        onKeyDown={e => this.handleAccountsKeyDown(e, false)}
242→        data-section="my account"
243→        data-link="my account"
244→        data-testid="my-account"
245→        onClick={event => {
246→          trackAnalyticsEvent(event);
247→          if (this.simple && this.isUserLoggedIn) {
248→            event.preventDefault();
249→          }
250→        }}
251→      >
252→        {this.renderAccountContent()}
253→      </a>
254→    );
255→  }
256→
257→  private renderCartAndAccount() {
258→    return (
259→      <Fragment>
260→        <ci-favorites
261→          dataSection="favorites"
262→          dataLink="favorites"
263→        />
264→        <div class="accounts" onMouseEnter={this.handleMouseEnter} onMouseLeave={this.handleMouseLeave}>
265→          <div class="accounts-trigger-group">
