290→          <ci-cart
291→            pricing={this.cartPricing}
292→            detail={this.cartDetail}
293→            detailedQuantities={this.detailedQuantities}
294→            data-section="my cart"
295→            data-link="my cart"
296→            onClick={trackAnalyticsEvent}
297→          />
298→        )}
299→      </Fragment>
300→    );
301→  }
302→
303→  private handleShowModal = e => {
304→    this.dialog.openModal(e);
305→  };
306→
307→  private handleShowChat = e => {
308→    e.preventDefault();
309→    (this.$el.querySelector('#LP_') as HTMLElement)?.click();
310→    this.dialog.forceClose();
311→  };
312→
313→  private handleSkipLink = (e: MouseEvent) => {
314→    e.preventDefault();
315→    const mainContent = (document.querySelector('main') || document.getElementById('root')) as HTMLElement;
316→    if (mainContent) {
317→      mainContent.setAttribute('tabindex', '-1');
318→      mainContent.focus();
319→      mainContent.scrollIntoView({ behavior: 'smooth' });
320→    }
321→  };
322→
323→  render() {
324→    const onMenuBtnClick = () => {
325→      this.visibleMenuBtn = !this.visibleMenuBtn;
326→      const ciBodyTag = document.getElementsByTagName('body')[0] as HTMLElement;
327→
328→      if (this.visibleMenuBtn) {
329→        this.visibleMobileVisibility = !this.visibleMobileVisibility;
330→        // Hotfix body scrolling issue on iOS 26. Backwards compatible for older versions. Works both on Android and iOS.
331→        ciBodyTag.style.position = 'fixed';
332→        ciBodyTag.style.width = '100%';
333→        ciBodyTag.style.overflow = 'hidden';
334→      } else {
335→        setTimeout(() => {
336→          this.visibleMobileVisibility = !this.visibleMobileVisibility;
337→          // Hotfix body scrolling issue on iOS 26. Backwards compatible for older versions. Works both on Android and iOS.
338→          ciBodyTag.style.position = '';
339→          ciBodyTag.style.top = '';
340→          ciBodyTag.style.width = '';
341→          ciBodyTag.style.overflow = 'visible';
342→        }, 200);
343→      }
344→    };
345→    return (
346→      <Host class={{ 'simple-header': this.simple }}>
347→        <a href="#main-content" class="skip-link" onClick={this.handleSkipLink}>
348→          Skip to main content
349→        </a>
350→        <div
351→          class={{
352→            overlay: true,
353→            activeOverlay: this.visibleOverlay,
354→            closeOverlay: !this.visibleOverlay,
355→          }}
356→        />
357→        {!this.simple && <ci-announcement-banner isPromoEnabled={this.isPromoEnabled} />}
358→        {!this.simple && !this.isPromoEnabled && (
359→          <div class="banner-container">
360→            <div class="banner">
361→              <div class="banner-title">
362→                <span class="banner-title--desktop">{this.desktopBannerMessage}</span>
363→                <span class="banner-title--mobile">{this.mobileBannerMessage}</span>
364→              </div>
365→              <div class="banner-actions">
366→                <a
367→                  class="banner-ttarpMobile ciHeader-phoneNumberLink"
368→                  href={`tel:${this.dynamicServiceNumber}`}
369→                  data-section="mobile banner"
370→                  data-link="help"
371→                  onClick={trackAnalyticsEvent}
372→                >
373→                  <img class="banner-ttarpMobile-icon" src={phone} alt="phone icon" />
374→                  <span class="banner-ttarpMobile-text">Help</span>
375→                </a>
376→              </div>
377→            </div>
378→          </div>
379→        )}
380→        <div class="main-container">
381→          <div
382→            class={{
383→              ciHeader: true,
384→              simple: this.simple,
385→            }}
386→          >
387→            <div class="ciHeader-subNav">
388→              <div
389→                class={{
390→                  'ciHeader-mobile-menu-btn': true,
391→                  'active': this.visibleMenuBtn,
392→                }}
393→                id="menuButton"
394→                onClick={onMenuBtnClick}
395→              >
396→                <span />
397→                <span />
398→                <span />
399→              </div>
400→              <ci-mobile-subnav
401→                isUserLogged={this.isUserLoggedIn}
