407→              <a href={`${process.env.CI_HOSTNAME}`} class="ciHeader-logo" role="link">
408→                <picture>
409→                  {this.simple && <source media="(max-width: 699px)" srcSet={logo} />}
410→                  <img alt="customink logo - inky" class="ciHeader-logo-image" src={logoLargeHorizontal} />
411→                </picture>
412→              </a>
413→            </div>
414→            {!this.simple && !this.isFramer && <ci-search id="searchOverlay" isItForPrerenderedView={true}></ci-search>}
415→            {this.renderHelpMenu()}
