426→                }}
427→                onCloseOverlay={() => {
428→                  this.visibleOverlay = false;
429→                }}
430→              ></ci-navigation>
431→              {this.renderCartAndAccount()}
432→            </div>
433→          </div>
434→        )}
435→      </Host>
436→    );
437→  }
438→}
